const o=`{% block sw_order_create_invalid_promotion_modal %} <sw-modal :title="$t('sw-order.invalidPromotionModal.modalTitle')" variant="small" class="sw-order-create-invalid-promotion-modal" @modal-close="onClose" > {% block sw_order_create_invalid_promotion_modal_description %} <p class="sw-order-create-invalid-promotion-modal__description"> {{ $t('sw-order.invalidPromotionModal.modalDescription') }} </p> {% endblock %} {% block sw_order_create_invalid_promotion_modal_lists %} <template v-for="item in invalidPromotionCodes" :key="item.code" > <li> - <strong>{{ item.code }}</strong> </li> </template> {% endblock %} {% block sw_order_create_invalid_promotion_modal_actions %} <template #modal-footer> {% block sw_order_create_invalid_promotion_modal_actions_confirm %} <mt-button variant="primary" size="small" data-analytics-id="sw-order-create-invalid-promotion-modal.confirm" @click="onConfirm" > {{ $t('sw-order.invalidPromotionModal.buttonConfirm') }} </mt-button> {% endblock %} </template> {% endblock %} </sw-modal> {% endblock %}`,{Store:i}=Shopware,t={template:o,emits:["close","confirm"],computed:{invalidPromotionCodes(){return i.get("swOrder").invalidPromotionCodes}},methods:{onClose(){this.$emit("close")},onConfirm(){this.$emit("confirm")}}};export{t as default};
